<?php declare(strict_types=1); namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; final class BtaqSchedule extends Model{protected $fillable=['btaq_group_id','day_of_week','start_time','end_time','room','teacher_employee_id','effective_start_date','effective_end_date','is_active','notes']; protected function casts():array{return ['is_active'=>'boolean','effective_start_date'=>'date','effective_end_date'=>'date'];} public function group():BelongsTo{return $this->belongsTo(BtaqGroup::class,'btaq_group_id');} public function teacher():BelongsTo{return $this->belongsTo(Employee::class,'teacher_employee_id');}}
